#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
    controller->has_valid_turbidity = false;
    controller->has_valid_level = false;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    bool previous_filter_on = controller->filter_on;
    bool previous_drain_open = controller->drain_open;
    controller_state_t previous_state = controller->state;
    uint32_t current_time_ms = input.now_ms;

    /* Check for stale sensor data - if either sensor is > 1000ms old, go to safe idle */
    bool sensors_stale = false;
    if (controller->has_valid_turbidity && current_time_ms - controller->last_turbidity_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        sensors_stale = true;
    }
    if (controller->has_valid_level && current_time_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        sensors_stale = true;
    }

    /* Handle malformed input or timeout */
    if (input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL ||
        input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_NONE) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = (previous_filter_on != false) || (previous_drain_open != false) || (previous_state != CONTROLLER_STATE_SAFE_IDLE);
        return output;
    }

    /* Update sensor data */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = current_time_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = current_time_ms;
        break;
    default:
        /* Invalid or no input */
        sensors_stale = true;
        break;
    }

    /* Check for stale sensor data - if either sensor is > 1000ms old, go to safe idle */
    if (sensors_stale) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = (previous_filter_on != false) || (previous_drain_open != false) || (previous_state != CONTROLLER_STATE_SAFE_IDLE);
        return output;
    }

    /* Check for LEVEL < 15 - stay in COMPLETE with filter off and drain closed */
    if (controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = (previous_filter_on != false) || (previous_drain_open != false) || (previous_state != CONTROLLER_STATE_SAFE_IDLE);
        return output;
    }

    /* Process based on current state */
    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        /* Stay in safe idle until both sensors have been seen validly */
        if (controller->has_valid_turbidity && controller->has_valid_level) {
            /* Now we have valid data, check control policy */
            int turbidity = controller->last_turbidity_ntu;
            int level = controller->last_level;

            if (turbidity > CONTROLLER_CLEAR_THRESHOLD_NTU && level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Start filtering */
                controller->filter_on = true;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_FILTERING;
                controller->clear_streak_count = 0;
            } else if (level < CONTROLLER_COMPLETE_LEVEL) {
                /* Level too low, stay idle */
                controller_set_safe_idle(controller);
            } else {
                /* Normal level, stay in safe idle until clear streak reaches 3 */
                // Nothing to do yet
            }
        }
        break;

    case CONTROLLER_STATE_FILTERING:
        if (controller->has_valid_turbidity) {
            int turbidity = controller->last_turbidity_ntu;

            /* TURB > 35 resets the clear streak */
            if (turbidity > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                controller->clear_streak_count = 0;
            } else {
                /* TURB <= 35, increment clear streak */
                controller->clear_streak_count++;

                /* Check if we should enter SETTLING (streak >= 3 and level >= 40) */
                if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED && 
                    controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    /* Enter SETTLING */
                    controller->filter_on = false;
                    controller->drain_open = false;
                    controller->state = CONTROLLER_STATE_SETTLING;
                    controller->settling_started_ms = current_time_ms;
                }
            }
        } else {
            /* No valid turbidity, stay in filtering */
        }

        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = CONTROLLER_STATE_FILTERING;
        output.state_name = "STATE FILTERING";
        output.changed = (previous_filter_on != controller->filter_on) || 
                         (previous_drain_open != controller->drain_open) || 
                         (previous_state != CONTROLLER_STATE_FILTERING);
        return output;

    case CONTROLLER_STATE_SETTLING:
        /* Check for disturbance - TURB > 40 resets streak and returns to FILTERING */
        if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            controller->clear_streak_count = 0;
            controller->filter_on = true;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_FILTERING;
        }

        /* Check if settling time has elapsed (>= 400ms) with latest clear sample */
        if (current_time_ms - controller->settling_started_ms >= CONTROLLER_SETTLING_MS && 
            controller->has_valid_turbidity && 
            controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            /* Enter DRAINING */
            controller->filter_on = false;
            controller->drain_open = true;
            controller->state = CONTROLLER_STATE_DRAINING;
        }

        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_filter_on != controller->filter_on) || 
                         (previous_drain_open != controller->drain_open) || 
                         (previous_state != controller->state);
        return output;

    case CONTROLLER_STATE_DRAINING:
        /* Check for disturbance - TURB > 50 AND LEVEL >= 40 closes drain and restarts filtering */
        if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->drain_open = false;
            controller->filter_on = true;
            controller->clear_streak_count = 0;
            controller->state = CONTROLLER_STATE_FILTERING;
        } else if (controller->has_valid_turbidity && controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
            /* Drain completed successfully */
            controller->filter_on = false;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_COMPLETE;
        }

        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_filter_on != controller->filter_on) || 
                         (previous_drain_open != controller->drain_open) || 
                         (previous_state != controller->state);
        return output;

    default:
        break;
    }

    /* Update output */
    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_filter_on != controller->filter_on) || 
                     (previous_drain_open != controller->drain_open) || 
                     (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

