static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

static bool temperature_is_rising_check(const controller_t *controller, int new_temp)
{
    if (!controller->has_valid_sensor) {
        return false;
    }
    return new_temp > controller->last_temperature_c;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}



static void controller_handle_low_temp(controller_t *controller, int temp)
{
    /* TEMP < 47: turn heater on */
    controller->heater_on = true;
    controller->state = CONTROLLER_STATE_HEATING;
}

static void controller_handle_high_temp(controller_t *controller, int temp)
{
    /* TEMP > 52: turn heater off, SAFE_OFF state */
    controller_set_safe_off(controller);
}

static void controller_handle_mid_low_temp(controller_t *controller, int temp)
{
    /* 47 <= TEMP < 50: hold previous safe actuator state (HOLDING) */
    controller->state = CONTROLLER_STATE_HOLDING;
    /* Keep heater_on as is - preserve previous state */
}

static void controller_handle_mid_high_temp_rising(controller_t *controller, int temp)
{
    /* 50 <= TEMP <= 52 and rising: turn heater off early, HOLDING state */
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_HOLDING;
}

static void controller_handle_mid_high_temp_stable(controller_t *controller, int temp)
{
    /* 50 <= TEMP <= 52 and not rising: hold previous safe actuator state */
    controller->state = CONTROLLER_STATE_HOLDING;
    /* Keep heater_on as is - preserve previous state */
}

static void controller_handle_timeout(controller_t *controller, uint32_t now_ms)
{
    /* No valid sensor for > 1000ms: turn heater off (SAFE_OFF) */
    if ((uint32_t)(now_ms - controller->last_valid_sensor_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        controller_set_safe_off(controller);
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Handle timeout check first for any input type */
    controller_handle_timeout(controller, input.now_ms);

    switch (input.kind) {
    case CONTROLLER_INPUT_NONE:
        /* No input - keep state as is if we have valid sensor, otherwise stay safe off */
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        /* Explicit timeout: turn heater off (SAFE_OFF) */
        controller_set_safe_off(controller);
        output.timed_out = true;
        break;

    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        /* Malformed input: turn heater off (SAFE_OFF) */
        controller_set_safe_off(controller);
        break;

    case CONTROLLER_INPUT_TEMPERATURE:
        {
            int previous_temperature = 0;

            if (controller->has_valid_sensor) {
                previous_temperature = controller->last_temperature_c;
            }

            controller->has_valid_sensor = true;
            controller->last_temperature_c = input.temperature_c;
            controller->last_valid_sensor_ms = input.now_ms;

            /* Apply control policy based on temperature */
            if (input.temperature_c < 47) {
                controller_handle_low_temp(controller, input.temperature_c);
            } else if (input.temperature_c > 52) {
                controller_handle_high_temp(controller, input.temperature_c);
            } else if (input.temperature_c >= 47 && input.temperature_c < 50) {
                controller_handle_mid_low_temp(controller, input.temperature_c);
            } else if (input.temperature_c >= 50 && input.temperature_c <= 52) {
                /* Check if temperature is rising for anticipatory heater-off */
                /* Use the previous temperature saved before update */
                bool was_rising = (previous_temperature != 0 && input.temperature_c > previous_temperature);

                if (was_rising) {
                    controller_handle_mid_high_temp_rising(controller, input.temperature_c);
                } else {
                    controller_handle_mid_high_temp_stable(controller, input.temperature_c);
                }
            }
        }
        break;

    default:
        /* Unknown input type: fail safe to heater off */
        controller_set_safe_off(controller);
        break;
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

